scwin.f_Retrieve = async function () {
  var chkVal = await $c.gus.cfValidate($p, [ed_brthngRateStDt, ed_brthngRateEndDt]);
  if (!chkVal) {
    return;
  }
  var chkCal = await scwin.f_termChk(ed_brthngRateStDt, ed_brthngRateEndDt);
  if (chkCal) {
    return;
  }
  $c.sbm.execute($p, sbm_condition);
};
scwin.f_termChk = async function (stObj, endObj) {
  if (stObj.getValue().trim() > endObj.getValue().trim()) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_045, ['입항(예정)일자']); //기간 체크
    stObj.focus();
    return true;
  }
  return false;
};

