scwin.sbm_brthngRate_submitdone = function (e) {
  if (ds_List1.getRowCount() == 0) {
    $c.win.alert($p, "접안료등록을 먼저 하십시요."); // 해당되는 자료가 존재하지 않습니다	
  } else {
    scwin.f_Caln(ds_List1.getRowCount());
  }
};
scwin.gr_List_onviewchange = function (info) {
  console.log(info);
  var row = info.rowIndex;
  var columnId = info.colId;
  if (columnId == "cvsslMgntNo") {
    scwin.f_openCommonPopUp(2, ds_List.getCellData(row, columnId), '', '', 'T');
  } else if (columnId == "clntNm") {
    scwin.f_openCommonPopUp(3, ds_List.getCellData(row, 'clntNo'), ds_List.getCellData(row, columnId), '', 'T');
  }
};

//-------------------------------------------------------------------------
// 대문자 입력
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
  this.setValue(e.target.value.toUpperCase());
};
scwin.gr_List_oneditkeyup = function (info) {
  const inputEl = event.target;
  switch (info.colID) {
    case "cvsslMgntNo":
      inputEl.value = info.newValue.toUpperCase();
      break;
    default:
      break;
  }
};
scwin.sbm_save_submitdone = function (e) {
  console.log(e.responseJSON.resultDataSet);
  if (e.responseJSON.resultDataSet[0].Code == 0) {
    $c.win.alert($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    scwin.f_Retrieve();
  }
};
